mapper.select:
SELECT * FROM ( SELECT a.*, ROWNUM rnum FROM ( SELECT c.center_id AS centerId, c.center_name AS centerName, c.center_region AS centerRegion, c.center_content AS centerContent, c.latitude, c.longitude, c.created_at AS createdAt, st.category AS category, st.base_fee AS baseFee, COUNT(DISTINCT r.room_id) AS roomCount, COUNT(DISTINCT cr.account_id) AS reviewCount, ROUND(AVG(cr.grade), 1) AS avgGrade, MIN(r.room_id) AS firstRoomId FROM centers c LEFT JOIN rooms r ON c.center_id = r.center_id LEFT JOIN sports_type st ON r.sport_id = st.sport_id LEFT JOIN centers_reviews cr ON c.center_id = cr.center_id WHERE 1=1
AND c.center_region = #{region}
AND st.category = #{category}
AND EXISTS ( SELECT 1 FROM room_slots rs2 JOIN rooms r2 ON rs2.room_id = r2.room_id WHERE r2.center_id = c.center_id AND TO_CHAR(rs2.slot_date, 'YYYY-MM-DD') = #{date} AND rs2.status = 'AVAILABLE' )
GROUP BY c.center_id, c.center_name, c.center_region, c.center_content, c.latitude, c.longitude, c.created_at, st.category, st.base_fee
ORDER BY st.base_fee ASC
ORDER BY st.base_fee DESC
ORDER BY reviewCount DESC, ROUND(AVG(cr.grade), 1) DESC, c.created_at DESC
ORDER BY c.created_at DESC
) a WHERE ROWNUM <= (#{offset} + #{pageSize}) ) WHERE rnum > #{offset}
